import React, { useRef, useEffect } from 'react';

function SignalChart({ data, tOn, tOff }) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);
    const W = rect.width;
    const H = rect.height;
    const PAD_L = 45;
    const PAD_R = 10;
    const PAD_T = 10;
    const PAD_B = 10;
    const plotW = W - PAD_L - PAD_R;
    const plotH = H - PAD_T - PAD_B;

    // Clear
    ctx.clearRect(0, 0, W, H);

    // Background
    ctx.fillStyle = '#fafafa';
    ctx.fillRect(PAD_L, PAD_T, plotW, plotH);

    // Compute Y range
    let yMax = 3.0;
    if (data.length > 0) {
      const maxVal = Math.max(...data.map((d) => d.y));
      yMax = Math.max(maxVal * 1.2, tOn * 1.5, 2.0);
    }

    const toX = (i) => PAD_L + (i / 99) * plotW;
    const toY = (v) => PAD_T + plotH - (v / yMax) * plotH;

    // Grid lines
    ctx.strokeStyle = '#e8e8ec';
    ctx.lineWidth = 1;
    const yTicks = [0, yMax * 0.25, yMax * 0.5, yMax * 0.75, yMax];
    yTicks.forEach((v) => {
      const y = toY(v);
      ctx.beginPath();
      ctx.moveTo(PAD_L, y);
      ctx.lineTo(PAD_L + plotW, y);
      ctx.stroke();
    });

    // Y axis labels
    ctx.fillStyle = '#999';
    ctx.font = '11px Inter, sans-serif';
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';
    yTicks.forEach((v) => {
      ctx.fillText(v.toFixed(1), PAD_L - 6, toY(v));
    });

    // T_ON reference line
    if (tOn <= yMax) {
      const y = toY(tOn);
      ctx.strokeStyle = '#e05555';
      ctx.lineWidth = 1.2;
      ctx.setLineDash([6, 3]);
      ctx.beginPath();
      ctx.moveTo(PAD_L, y);
      ctx.lineTo(PAD_L + plotW, y);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.fillStyle = '#e05555';
      ctx.font = '10px Inter, sans-serif';
      ctx.textAlign = 'right';
      ctx.fillText(`T_ON=${tOn}`, PAD_L + plotW, y - 4);
    }

    // T_OFF reference line
    if (tOff <= yMax) {
      const y = toY(tOff);
      ctx.strokeStyle = '#e0a030';
      ctx.lineWidth = 1;
      ctx.setLineDash([6, 3]);
      ctx.beginPath();
      ctx.moveTo(PAD_L, y);
      ctx.lineTo(PAD_L + plotW, y);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.fillStyle = '#e0a030';
      ctx.font = '10px Inter, sans-serif';
      ctx.textAlign = 'right';
      ctx.fillText(`T_OFF=${tOff}`, PAD_L + plotW, y - 4);
    }

    // Signal line
    if (data.length > 1) {
      ctx.strokeStyle = '#5b6abf';
      ctx.lineWidth = 2;
      ctx.lineJoin = 'round';
      ctx.beginPath();
      // Map data indices 0..data.length-1 into the plot
      data.forEach((pt, i) => {
        const x = toX(i);
        const y = toY(Math.min(pt.y, yMax));
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.stroke();
    }

    // Border
    ctx.strokeStyle = '#ddd';
    ctx.lineWidth = 1;
    ctx.strokeRect(PAD_L, PAD_T, plotW, plotH);
  }, [data, tOn, tOff]);

  return (
    <div className="card signal-card">
      <h3>Activation Signal</h3>
      <canvas
        ref={canvasRef}
        style={{ width: '100%', height: '180px', display: 'block' }}
      />
    </div>
  );
}

export default SignalChart;
